@RestController
class AuthorizationController {
    private final ClientDetailsService clientDetailsService;
    private final AuthorizationCodeServices authorizationCodeServices;
    private final Map<String, String> authorizationCodes = new ConcurrentHashMap<>();
    private final Map<String, Long> codeExpirations = new ConcurrentHashMap<>();

    public AuthorizationController(ClientDetailsService clientDetailsService,
                                  AuthorizationCodeServices authorizationCodeServices) {
        this.clientDetailsService = clientDetailsService;
        this.authorizationCodeServices = authorizationCodeServices;
        startExpirationCleanup();
    }

    @GetMapping("/oauth/authorize")
    public String authorize(@RequestParam String response_type,
                          @RequestParam String client_id,
                          @RequestParam String redirect_uri,
                          @RequestParam(required = false) String scope,
                          @RequestParam(required = false) String state) {
        try {
            ClientDetails client = clientDetailsService.loadClientByClientId(client_id);
            if (!validateRedirectUri(client, redirect_uri)) {
                throw new IllegalArgumentException("Invalid redirect_uri");
            }

            String code = generateAuthorizationCode();
            authorizationCodes.put(code, redirect_uri);
            codeExpirations.put(code, System.currentTimeMillis() + 600000); // 10 minutes

            return "Location: " + redirect_uri + "?code=" + code + "&state=" + state;
        } catch (ClientRegistrationException e) {
            throw new IllegalArgumentException("Invalid client_id");
        }
    }

    private boolean validateRedirectUri(ClientDetails client, String redirectUri) {
        if (redirectUri == null || redirectUri.isEmpty()) {
            return false;
        }

        String[] registeredUris = client.getRegisteredRedirectUri().toArray(new String[0]);
        if (registeredUris == null || registeredUris.length == 0) {
            return false;
        }

        try {
            URI redirect = new URI(redirectUri);
            String redirectHost = redirect.getHost();
            String redirectScheme = redirect.getScheme();

            for (String registeredUri : registeredUris) {
                if (registeredUri == null || registeredUri.isEmpty()) {
                    continue;
                }

                URI registered = new URI(registeredUri);
                String registeredHost = registered.getHost();
                String registeredScheme = registered.getScheme();

                if (!redirectScheme.equals(registeredScheme)) {
                    continue;
                }

                if (registeredHost == null) {
                    continue;
                }

                if (registeredHost.equals(redirectHost)) {
                    return true;
                }

                if (registeredHost.startsWith("*.")) {
                    String domain = registeredHost.substring(2);
                    if (redirectHost.endsWith("." + domain)) {
                        return true;
                    }
                }
            }
        } catch (URISyntaxException e) {
            return false;
        }

        return false;
    }

    private String generateAuthorizationCode() {
        return java.util.UUID.randomUUID().toString();
    }

    private void startExpirationCleanup() {
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
        scheduler.scheduleAtFixedRate(() -> {
            long currentTime = System.currentTimeMillis();
            codeExpirations.entrySet().removeIf(entry -> {
                if (entry.getValue() < currentTime) {
                    authorizationCodes.remove(entry.getKey());
                    return true;
                }
                return false;
            });
        }, 60, 60, TimeUnit.SECONDS);
    }
}